  "home":                       { "title": "GoldMoodAstro — Profesyonel Astroloji ve Tarot Danışmanlığı", "description": "Türkiye''nin onaylı astrolog, tarot uzmanı ve numerologlarıyla canlı görüşme. Doğum haritası, sinastri, günlük yorum ve kişiye özel rehberlik.", "og_image": "", "no_index": false },
  "birth-chart":                { "title": "Doğum Haritası Hesaplama ve Yorumlama", "description": "Swiss Ephemeris hassasiyetinde doğum haritası analizi. Gezegen pozisyonları, evler, açılar ve uzman astrolog yorumu — hemen başlayın.", "og_image": "", "no_index": false },
