  "pricing":                    { "title": "Fiyatlar ve Hizmet Paketleri", "description": "Ücretsiz ön görüşme, 15dk tanışma, 30/60/90dk derinlemesine seans seçenekleri. Şeffaf fiyatlandırma, gizli ücret yok.", "og_image": "", "no_index": false },
  "daily":                      { "title": "Günlük Burç Yorumları — Tüm Burçlar", "description": "12 burç için bugünün aşk, kariyer, sağlık ve genel yorumu. Profesyonel astrologlar tarafından gözden geçirilen günlük rehber.", "og_image": "", "no_index": false },
  "blog":                       { "title": "Astroloji ve Spiritüel Rehberlik Blogu", "description": "Astroloji, tarot, numeroloji ve kişisel gelişim üzerine derinlikli yazılar. Uzman danışmanlardan ipuçları, rehberler ve analizler.", "og_image": "", "no_index": false },
  "blog-post":                  { "title": "GoldMoodAstro Blog Yazısı", "description": "Astroloji ve spiritüel rehberlik üzerine uzman yazıları.", "og_image": "", "no_index": false },
  "about":                      { "title": "Hakkımızda — GoldMoodAstro", "description": "GoldMoodAstro''nun hikayesi, misyonu ve onaylı danışman ekibi. Türkiye''nin güvenilir astroloji ve spiritüel rehberlik platformu.", "og_image": "", "no_index": false },
  "contact":                    { "title": "İletişim ve Destek", "description": "GoldMoodAstro ile iletişime geçin. Sorularınız, danışman başvuruları ve kurumsal işbirlikleri için bizimle bağlantı kurun.", "og_image": "", "no_index": false },
  "faqs":                       { "title": "Sıkça Sorulan Sorular (SSS)", "description": "GoldMoodAstro hakkında en çok merak edilenler: nasıl çalışır, ödeme, gizlilik, danışman seçimi, randevu süreci ve daha fazlası.", "og_image": "", "no_index": false },
  "burclar":                    { "title": "Burçlar — 12 Burç Özellikleri ve Yorumları", "description": "Koç''tan Balık''a 12 burcun özellikleri, uyumu, günlük/haftalık/aylık yorumları. Burcunu öğren, derinlemesine analizini al.", "og_image": "", "no_index": false },
  "burclar-sign":               { "title": "Burç Özellikleri, Yorumları ve Uyumluluk", "description": "Bu burcun karakter özellikleri, güçlü ve zayıf yönleri, ünlüleri, uyumluluk haritası ve uzman astrolog yorumları.", "og_image": "", "no_index": false },
  "burclar-bugun":              { "title": "Bugünün Burç Yorumu", "description": "Bu burç için bugünün aşk, kariyer, sağlık ve genel yorumu. Günü en iyi nasıl değerlendireceğinin profesyonel rehberi.", "og_image": "", "no_index": false },
  "burclar-haftalik":           { "title": "Haftalık Burç Yorumu", "description": "Bu burç için bu haftanın detaylı astrolojik analizi. Aşk, kariyer, finans ve sağlık alanlarında haftalık rehber.", "og_image": "", "no_index": false },
  "burclar-aylik":              { "title": "Aylık Burç Yorumu", "description": "Bu burç için bu ayın gezegen geçişleri, dolunay ve yeni ay etkileri, ay boyunca odaklanılması gereken alanlar.", "og_image": "", "no_index": false },
  "burclar-ask":                { "title": "Aşk Burç Yorumu — İlişki Rehberi", "description": "Bu burcun aşk hayatında bu dönem ne bekliyor? İlişki dinamikleri, partner uyumu, romantik fırsatlar ve uzman tavsiyeleri.", "og_image": "", "no_index": false },
  "burclar-kariyer":            { "title": "Kariyer Burç Yorumu — İş Hayatı Rehberi", "description": "Bu burcun kariyer hayatında dikkat etmesi gerekenler, terfi fırsatları, finansal hareketler ve mesleki rehber.", "og_image": "", "no_index": false },
  "burclar-saglik":             { "title": "Sağlık Burç Yorumu — Beden ve Zihin", "description": "Bu burç için bedensel ve ruhsal sağlık tavsiyeleri. Astroloji penceresinden iyi hissetmek için pratik öneriler.", "og_image": "", "no_index": false },
  "burclar-uyumlulik":          { "title": "Burç Uyumluluk Haritası", "description": "Bu burç hangi burçlarla uyumlu? Aşk, dostluk ve iş ilişkilerinde uyum analizi, çift dinamikleri ve astrologdan tavsiyeler.", "og_image": "", "no_index": false },
  "burclar-meditasyon":         { "title": "Burç Meditasyonu ve Affirmasyonları", "description": "Bu burç için kısa sesli meditasyon, günlük affirmasyonlar ve element odaklı sakinleşme pratiği. Ruhsal denge ve içsel huzur için astroloji.", "og_image": "", "no_index": false },
  "burclar-pair-uyumu":         { "title": "İkili Burç Uyumu Analizi", "description": "İki burç arasındaki astrolojik uyum: sevgili, partner, arkadaş veya iş ortağı. Detaylı element, modalite ve gezegen analizi.", "og_image": "", "no_index": false },
  "burclar-transit":            { "title": "Aylık Gezegen Geçişleri ve Transit Analizi", "description": "Bu ayın gezegen geçişleri, dolunay/yeni ay etkileri ve burçlara genel etkisi. Astrolojik takvim ve uzman yorumları.", "og_image": "", "no_index": false },
  "yukselen-burc-hesaplayici":  { "title": "Yükselen Burç Hesaplayıcı — Anında Sonuç", "description": "Doğum tarihi, saati ve şehir ile yükselen burcunuzu hesaplayın. Yükselen burç anlamı, etkisi ve yorumu hemen.", "og_image": "", "no_index": false },
  "big-three":                  { "title": "Big Three — Güneş, Ay ve Yükselen Burcunuz", "description": "Astrolojinin üç temel direği: güneş burcu (kim olduğun), ay burcu (nasıl hissettiğin), yükselen burç (nasıl göründüğün).", "og_image": "", "no_index": false },
  "yildizname":                 { "title": "Yıldızname — Ebced ile Geleceğin Sırrı", "description": "Klasik Osmanlı astrolojisi yıldızname ile isim ve doğum tarihinden derin analiz. Ebced hesabı ve uzman yorumu.", "og_image": "", "no_index": false },
  "yildizname-result":          { "title": "Yıldızname Sonucunuz", "description": "Kişiye özel yıldızname analizi: karakter, geçmiş, gelecek ve önemli hayat dönüşümleri.", "og_image": "", "no_index": false },
  "tarot":                      { "title": "Tarot Falı — Klasik Rider-Waite ve Daha Fazlası", "description": "Tek kart, üçlü açılım veya Kelt Haçı ile tarot falı. AI destekli sembol yorumu + uzman astrolog danışmanlığı.", "og_image": "", "no_index": false },
  "tarot-reading":              { "title": "Tarot Açılımınızın Yorumu", "description": "Sizin için açılan kartların detaylı analizi. Geçmiş, şimdi ve geleceğe dair sembolik mesajlar.", "og_image": "", "no_index": false },
  "kahve-fali":                 { "title": "Kahve Falı — Geleneksel Türk Kahve Falı Online", "description": "Kahve fincanı fotoğrafınızı yükleyin, AI ve uzman desteğiyle geleneksel kahve falı yorumunuzu alın. Hızlı ve özel.", "og_image": "", "no_index": false },
  "kahve-fali-result":          { "title": "Kahve Falı Sonucunuz", "description": "Fincanınızda görülen sembollerin detaylı yorumu — aşk, kariyer, sağlık ve hayat yolu mesajları.", "og_image": "", "no_index": false },
  "ruya-tabiri":                { "title": "Rüya Tabiri — Rüyanızın Anlamı", "description": "Rüyanızı yazın, İslami ve psikolojik perspektifle yorumunu alın. Sembollerin derin anlamı, uyarılar ve müjdeler.", "og_image": "", "no_index": false },
  "ruya-tabiri-result":         { "title": "Rüya Tabiriniz", "description": "Rüyanızda gördüğünüz sembollerin yorumu, hayatınıza dair olası mesajlar ve rehberlik.", "og_image": "", "no_index": false },
